module top_module(clk, reset, write, data_input, out);parameter n = 64;

    input clk;
    input reset;
    input write;
    input [n - 1 : 0] data_input;

    output reg [n - 1 : 0] out;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            if(reset)
                out = 0;
            else
            if (write)
                out = data_input;
        end
endmodule
